def read_phrases(filepath: str) -> list[str]:
    """Legge le frasi da un file, una per riga."""
    phrases = []
    with open(filepath, encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if line:
                phrases.append(line)
    return phrases


def apply_fixes(phrases: list[str]) -> dict[str, str]:
    """Restituisce un dizionario con le traduzioni corrette per le frasi."""
    result = {}
    missing = []
    for phrase in phrases:
        if phrase in FIX_TRANSLATIONS:
            result[phrase] = FIX_TRANSLATIONS[phrase]
        else:
            missing.append(phrase)
    if missing:
        print(f"ATTENZIONE: {len(missing)} frasi non trovate nel dizionario:")
        for m in missing:
            print(f"  {m!r}")
    return result


if __name__ == "__main__":
    script_dir = Path(__file__).parent
    phrases_file = script_dir / "phrases_to_fix.txt"

    if not phrases_file.exists():
        print(f"File non trovato: {phrases_file}")
        raise SystemExit(1)

    phrases = read_phrases(str(phrases_file))
    fixes = apply_fixes(phrases)
    print(f"Traduzioni trovate: {len(fixes)} / {len(phrases)}")
    print(f"Voci nel dizionario FIX_TRANSLATIONS: {len(FIX_TRANSLATIONS)}")
